var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005-10: <color=#ffd34c>【부록-002】 영상 자료#2</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005-10：<color=#ffd34c>【付録-002】 映像資料#2</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005-10: <color=#ffd34c>【Appendix-002】 Video Material 2</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005-10: <color=#ffd34c>【附錄-002】 影像資料#2</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"히익! 타, 탄창이 떨어졌어. 누, 누가 아무나 지원 좀...!","JPN":"ひいっ！だ、弾薬が切れた。だ、誰か援護を……！","ENG":"Eek! I-I'm out of ammo. S-someone, I need support!","TWN":"咿！彈、彈匣掉了。是、是誰都好，快來支援我……！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"크어어......!","JPN":"クオオオ……！","ENG":"Grawwr!","TWN":"吼喔喔……！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_24"},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"크으...크르륵......","JPN":"クオ…グルル……","ENG":"Grr... Gwahh...","TWN":"吼喔……咕嚕嚕……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_FALL_DAMAGE_DOWN"},{"id":"L32_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"또 보는군, 공돌이 친구.","JPN":"また会ったな、メカニック君。","ENG":"Good to see you again, engineer.","TWN":"又見面了，工程仔的朋友。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다시 한 번 말해두지만 난 존 메이슨이다.","JPN":"もう一度言っておくが、俺の名前はジョン・メイソンだ。","ENG":"I told you, my name is John Mason.","TWN":"再跟你說一遍，我叫約翰•梅森。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래, 그래. 못 보던 사이에 업계에서 꽤 유명인사가 됐더군.","JPN":"ああ、そうだった。お前、いつの間にか業界の有名人になってたんだな。","ENG":"Yes, right. You've become quite famous while we were apart.","TWN":"是，是。好久沒見，你在業界裡都變成大名人了呢。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"용병사무소를 차렸다면서?","JPN":"傭兵事務所をやってるんだって？","ENG":"I heard that you have your own office now?","TWN":"聽說你開了家傭兵事務所？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그때 말 한 그 형이랑 같이 일하는 건가? 형이 장비를 만들고 자네가 사용하는?","JPN":"あの時言ってた兄貴と一緒にやってるのか？兄貴が装備を作って、お前が使うって感じで？","ENG":"Are you working together with that brother of yours? Your brother makes the weapons and you use 'em?","TWN":"那你是跟當時提到的哥哥一起工作嗎？你哥做裝備，然後你來使用？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그랬으면 좋았겠지만, 우리 형이 꽤 성급한 성격이라서 말이지.","JPN":"だとよかったんだが、兄貴はせっかちでな。","ENG":"I wish that was the case, but my brother is quite impatient.","TWN":"要是能那樣就太好了，但我哥的性子非常急。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"벌써 세상 떠나 버릴 정도로 성격이 급해서...... 동업은 못하게 됐어.","JPN":"俺より先にこの世を去っちまって……仕事仲間にはなれなかった。","ENG":"Impatient enough to live me behind in this world already... We're not together any more.","TWN":"急到已經離開這個世界了……所以沒辦法合夥了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......그런가.","JPN":"……そうか。","ENG":"I see.","TWN":"……是嗎。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"원래 좋은 사람들이 좋은 곳으로 먼저 가는 법이지.","JPN":"いい人は、早く逝ってしまうもんだ。","ENG":"The good people usually leave first.","TWN":"本來，好人總是會先去好地方。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......그나저나 알고 보니 당신 꽤 유명하던데?","JPN":"……そういえばあんた、かなり有名なんだな。","ENG":"Anyway, I also found out that you're quite famous as well.","TWN":"……話說回來，你還挺有名啊？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"베테랑 용병이 필요할 때, 웬만한 업주들은 당신 이름을 먼저 찾더군.","JPN":"ベテラン傭兵が必要な時、業者が真っ先に口にするのは、あんたの名前だった。","ENG":"Whenever someone needs a veteran mercenary, your name usually comes up first.","TWN":"需要老手傭兵時，大部分的雇主都會先搜尋你的名字。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"당신과 같이 일선에서 활약했단 사실만으로도 들어오는 일감이 많더라고.","JPN":"あんたと一線で活躍したってだけで、仕事を依頼する業者もいた。","ENG":"Even I was able to get a lot of jobs because I had experience working with you.","TWN":"光是有和你在一線一起工作的經歷，就讓我接到了很多工作。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런데......","JPN":"だが……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"듣자니 돈 많이 주는 일감들만 찾아 다니는 것 같더군.","JPN":"金になる依頼以外は、すべて断ってるようだな。","ENG":"I heard that you only go around looking for high paying jobs.","TWN":"聽說你只接報酬多的工作。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"실력은 인정하겠지만, 너무 무리하는 거 아닌가?","JPN":"あんたの腕は認めるが、少し無理をしてるんじゃないか？","ENG":"I admit that you're good, but aren't you pushing yourself a bit too hard?","TWN":"雖然我認可你的實力，但你會不會太勉強了？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......자식을 키우면 돈이 나가는 법이니까.","JPN":"……子育てには金がかかるんだ。","ENG":"You can never have enough when you're raising a kid.","TWN":"……養小孩是很花錢的。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"자네 같은 독신남은 이해 못할 거야.","JPN":"お前のような独り身にはわからないだろう。","ENG":"Single people will never understand.","TWN":"像你這樣的單身漢是無法理解的吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"흐음...... 자식들 대학 학자금이라도 필요한 건가?","JPN":"ふむ……子供の学費でも貯めてるのか？","ENG":"Hmm... Are you paying off student loans for your kid or something?","TWN":"呃……是需要繳小孩的大學學費嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 나 그 정도로 안 늙었어.","JPN":"おい、俺はそこまで年じゃない。","ENG":"Hey, I'm not that old.","TWN":"喂，我還沒老到那種程度。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"보통 노인들이 자신의 노화를 부정하곤 하지.","JPN":"年寄りは自分の老化を否定するもんだ。","ENG":"That's what old people say to defend their age.","TWN":"老人通常都會否定自己很老。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그보다 애들은 어때? 아들? 딸?","JPN":"それより子供って息子か？それとも娘？","ENG":"Anyway, how's your kid? Son? Daughter?","TWN":"話說你的孩子是兒子還是女兒？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"눈에 넣어도 안 아플 딸아이지.","JPN":"目に入れても痛くないほど可愛い娘だ。","ENG":"A precious girl I am willing to die for.","TWN":"是放到眼睛裡也不會痛的女兒。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"다음에 한 번 보러 오라고. 내 딸이라서 하는 말이 아니라 정말 귀엽다니까?","JPN":"今度見に来るといい。本当に可愛いんだ。","ENG":"Feel free to come visit her next time. I'm not saying this because she's mine, but she's really cute.","TWN":"下次有機會來看看她吧。不是因為是我的女兒才這樣說，但她真的很可愛喔？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"세상에...... 그 베테랑 에디가 딸바보 아빠일 줄은 몰랐군.","JPN":"驚きだな……あのベテラン傭兵のエディーが、まさか親バカだったとは。","ENG":"Good lord... I never imagined the veteran Eddie to be a doting dad.","TWN":"我的天……沒想到那個老手傭兵艾迪居然是個女兒控。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 그 애를 위해서라도 너무 위험을 자처하진 말라고.","JPN":"なら、その子のためにも危険な任務は控えろよ。","ENG":"Then you should really try to play it safe for that kid.","TWN":"那也算是為了她，你不要太拼命了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이건 그쪽이 너무 열심히 하는 탓에 내 일감이 줄어들까 우려돼서 하는 말이야.","JPN":"別に心配してるわけじゃない。あんたが仕事を頑張りすぎると、俺の仕事が減るからな。","ENG":"I'm just worried that, at this rate, you're going to take over my work load as well.","TWN":"你太拼命的話，我會怕你把我的工作都搶走了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"참견 고맙군. 마음은 잘 받도록 하지.","JPN":"親切なアドバイス、ありがとよ。","ENG":"Thank you for meddling. But I will only accept your kind heart.","TWN":"多謝你的關心，我會記在心裡的。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"8시 방향! 더 몰려온다! 대형 침식체도 섞여있으니 조심해!","JPN":"8時方向！もっと攻め込んでくるぞ！大型の侵食体も交じってるから気をつけろ！","ENG":"8 o'clock! More of them are coming! Watch out! It's a mixed group with giant C.O.!","TWN":"8點鐘方向！有更多的敵人湧過來了！還夾雜著大型侵蝕體，小心點！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"하지만, 이제 와서 물러설 생각은 없어.","JPN":"だが、今さら身を引くつもりはない。","ENG":"But I have no intention of backing off now.","TWN":"但事到如今，我也沒有退縮的打算。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래, 어차피 이런 이야길 들을 거라곤 기대도 안 했다.","JPN":"ああ、そう言うと思ったよ。","ENG":"Yeah, I didn't expect to hear your story either.","TWN":"是啊，反正我也不期待你會把這種話聽進去。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"헉...... 헉......","JPN":"はあ……はあ……","ENG":"*Pant* *Pant*","TWN":"呼……呼……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후우...... 아슬아슬했군.","JPN":"ふう……ギリギリだったな。","ENG":"*Whew* That was close.","TWN":"呼……真是驚險啊。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"침식체 반응 완전 소실! 작전 종료!","JPN":"侵食体反応、完全消失！作戦終了！","ENG":"All C.O. signals eliminated! Mission complete!","TWN":"侵蝕體的反應完全消失！作戰結束！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......끝났군. 고생 많았어.","JPN":"……終わったな。ご苦労だった。","ENG":"It's over. Great work.","TWN":"……結束了呢，辛苦了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어딜 그렇게 바쁘게 가나? 작전도 끝났는데 술이나 한잔 하자고.","JPN":"どこへ行くんだ？作戦も終了したことだし、酒でも一杯どうだ？","ENG":"Where are you headed off to? We're all done here, let's grab a drink or something.","TWN":"這麼急著走幹嘛？作戰結束後就一起來喝一杯啊。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......미안하지만 다른 회사와 미리 선약을 잡아둬서 말이야.","JPN":"……悪いが、別の会社との先約があるんだ。","ENG":"I'm sorry, but I have another appointment with a different company.","TWN":"……對不起，我已經和其他公司有約了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"한 고비 넘기자마자 또 임무에 나가는 건가?","JPN":"死線をくぐったってのに、また仕事か？","ENG":"Another mission after barely surviving one?","TWN":"才剛過一個難關，你馬上又要出任務啊？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아무리 돈이 중요해도, 이쯤 되면 사람이 어리석어 보이는데.","JPN":"いくら金が大事でも、ここまでくればただのバカにしか見えんな。","ENG":"No matter how important money is to you, this just seems foolish.","TWN":"就算錢再怎麼重要，一個人做到這個地步也太蠢了吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"걱정 마. 아무리 힘들어도 내겐 수호천사님이 계시니까.","JPN":"心配するな。どんなに大変でも、俺には可愛い天使がついてる。","ENG":"Don't worry. No matter how hard, I have a guardian angel with me.","TWN":"別擔心，就算再怎麼辛苦，我也有我的守護天使。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"딸아이의 미소만 지킬 수 있다면, 이런 고초 따윈 우습지.","JPN":"娘の笑顔を守れるなら、この程度の苦労は屁でもない。","ENG":"If I can keep the smile on my daughter's face, then this is nothing.","TWN":"只要能守住女兒的笑容，這點辛苦根本不算什麼。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......나도 나중에 당신처럼 될까 봐, 슬슬 걱정되기 시작했어.","JPN":"……いつか俺も、あんたみたいになりそうで怖いな。","ENG":"I'm starting to worry that I'm going to turn out like you in the future.","TWN":"……我開始擔心我以後會不會變得跟你一樣了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이거 받아.","JPN":"ほら、あんたの分だ。","ENG":"Take this.","TWN":"接住。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......탄창?","JPN":"……弾倉か？","ENG":"A magazine?","TWN":"……彈匣？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"존 메이슨의 대 침식전용 특제 이터니움탄이다.","JPN":"対侵食戦用、特製エタニウム弾だ。","ENG":"They're special Anti-corruption Eternium ammo made by yours truly.","TWN":"這是約翰·梅森對侵蝕體專用的特製永恆之金子彈。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"초짜일 때 받은 교육비 대신이라고 생각해.","JPN":"素人だった頃の教育費だと思え。","ENG":"Consider it a payment for the lesson you gave me when I was new.","TWN":"就當是我新手時的學費吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......고맙군. 요긴하게 쓰도록 하지.","JPN":"……ありがたく使わせてもらうよ。","ENG":"Thanks. I'll make good use of it.","TWN":"……謝啦，我會好好使用的。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"주문제작도 받고 있으니 마음에 들면 연락하라고.","JPN":"オーダーメイドも受け付けてるから、気に入ったら連絡をくれ。","ENG":"I'm still open for custom orders. Just look me up if you like them.","TWN":"子彈也接受訂做，你喜歡的話就聯絡我吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......방금 고맙단 발언은 철회하겠어.","JPN":"……感謝の気持ちが台無しだ。","ENG":"I'm going to take back my thank you then.","TWN":"……我想收回我剛剛道謝的話。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하하, 그럼...... 다음에는 그 귀엽다는 따님이나 만나게 해달라고.","JPN":"はは、それじゃあ……今度は、その可愛い娘さんに会わせてくれ。","ENG":"Hah hah, anyway... Promise to introduce me to that cute daughter of yours next time.","TWN":"哈哈，總之……下次讓我見見你那可愛的女兒吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래. 보면 놀랄 거다. 천사도 그런 천사가 없거든.","JPN":"ああ、きっと驚くぞ。本当に天使のような子なんだ","ENG":"Yes. You'll be surprised. She's such an angel.","TWN":"好啊，你看了肯定會嚇一跳，沒有天使比她更天使了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"기대하지. 살아서 또 보자고.","JPN":"期待してるよ。また生きて会おう。","ENG":"I look forward to it. I'll see you again alive.","TWN":"我會期待的，我們活著再見面吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};